mapper.select:
select s.id, s.category_id, s.name, s.price, s.status, s.description, s.image, s.update_time, c.name as categoryName from setmeal as s left join category as c on c.id = s.category_id
and s.name like concat('%',#{name},'%') and s.category_id = #{categoryId} and s.status = #{status}
order by s.create_time desc
